const sd = $getWorkflowStaticData('global');
sd.angefragt = sd.angefragt || [];
const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at && o.email);
const raus = [];

for (const o of orders) {
  if (sd.angefragt.includes(o.id)) continue;
  const vorname = (o.customer && o.customer.first_name) || '';
  const artikel = (o.line_items || []).map(li => li.title).slice(0, 3).join(', ');

  const prompt = 'Du bist E-Mail-Marketing-Profi fuer den Onlineshop "' + setup.SHOP_NAME + '".\n' +
    'Der Kunde hat vor ' + setup.TAGE_NACH_BESTELLUNG + ' Tagen bestellt und die Ware erhalten. Schreibe eine kurze, herzliche Bewertungs-Anfrage auf Deutsch (Du-Form), maximal 100 Woerter.\n\n' +
    'Daten:\n- Vorname: ' + (vorname || 'unbekannt (neutral anreden)') + '\n- Gekaufte Artikel: ' + artikel + '\n- Bewertungs-Link: ' + setup.BEWERTUNG_LINK + '\n\n' +
    'Anforderungen: Ehrlich fragen wie zufrieden er ist, EIN klarer Button (als <a> mit Inline-Button-Styling) zum Bewertungs-Link, erwaehne dass es nur 60 Sekunden dauert. Extra-Kick: Bitte ihn, ein Foto/Video mit dem Produkt zu posten und den Shop zu markieren. Kein Betteln, kein Spam-Ton. Mobiltaugliches HTML mit Inline-CSS.\n' +
    'Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "<komplettes E-Mail-HTML>"}';

  raus.push({ json: { order_id: o.id, email: o.email, vorname, artikel, prompt } });
  sd.angefragt.push(o.id);
}

if (sd.angefragt.length > 1000) sd.angefragt = sd.angefragt.slice(-1000);
return raus;

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Wie zufrieden bist du? ⭐', html: text };
}
const orig = $('🧠 Filtern & Prompt bauen').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;
return { json: {
  empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + daten.betreff,
  email_html: daten.html
}};
